#include<bits/stdc++.h>
using namespace std;
const int N=10000010;
int n,m,k,fa[N],h[N],siz[N],top;
int p[N],q[N];
struct edge
{
    int x,y;
}e[N];
struct Stack
{
    int x,y,add;
}st[N];
vector<edge> t[N];
int find(int x)
{
    while(x!=fa[x])
    {
        x=fa[x];
    }
    return fa[x];
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(h[a]>h[b])
    {
        swap(a,b);
    }
    st[++top]=(Stack){a,b,(h[a]==h[b])};
    siz[b]+=siz[a];
    fa[a]=b;
    if(h[a]==h[b])
    {
        h[b]++;
    }
}
void update(int x,int l,int r,int L,int R,edge v)
{
    if(L>R||l>R||r<L)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    int mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
char c[N];
void solve(int x,int l,int r)
{
    int ans=1;
    int lst=top;
    for(auto i:t[x])
    {
        merge(i.x,i.y);
    }
    if(l==r)
    {
        if(c[l]=='Q')
        {
            printf("%lld\n",1ll*siz[find(p[l])]*siz[find(q[l])]);
        }
    }
    else
    {
        int mid=(l+r)>>1;
        solve(x<<1,l,mid);
        solve(x<<1|1,mid+1,r);
    }
    while(top>lst)
    {
        h[fa[st[top].x]]-=st[top].add;
        int k=st[top].x;
        while(fa[k]!=k)
        {
            k=fa[k];
            siz[k]-=siz[st[top].x];
        }
        fa[st[top].x]=st[top].x;
        top--;
    }
}
map<pair<int,int>,vector<int>> mp;
int main()
{
    scanf("%d%d",&n,&k);
    m=0;
    for(int i=1;i<=k;i++)
    {
        char op;
        int x,y;
        cin>>op;
        c[i]=op;
        scanf("%d%d",&x,&y);
        p[i]=x;
        q[i]=y;
        if(x>y)
        {
            swap(x,y);
        }
        mp[{x,y}].push_back(i);
    }
    for(auto i:mp)
    {
        vector<int> v=i.second;
        int siz=v.size()-1;
        int lst=v[0];
        for(int j=1;j<=siz;j++)
        {
            update(1,1,k,lst,v[j]-1,(edge){i.first.first,i.first.second});
            lst=v[j]+1;
        }
        update(1,1,k,v[siz]+1,k,(edge){i.first.first,i.first.second});
    }
    for(int i=1;i<=n*2;i++)
    {
        fa[i]=i;
        h[i]=1;
        siz[i]=1;
    }
    solve(1,1,k);
    return 0;
}
